import { z as z7 } from "zod";
var preferencesTool = createTool7({
  id: "preferences-tool",
  description: "Manages user preferences for external link destinations (Kraken vs CoinGecko/Yahoo Finance).",
  inputSchema: z7.object({
    action: z7.enum(["set", "get"]).describe("Action to perform on preferences"),
    linkPreference: z7.enum(["default", "kraken"]).optional().describe("Link preference: 'default' (CoinGecko/Yahoo) or 'kraken'"),
    userId: z7.string().optional().describe("User ID for personalized storage")
  }),
  outputSchema: z7.object({
    success: z7.boolean(),
    linkPreference: z7.string(),
    message: z7.string()
  }),
  execute: async ({ context, mastra: mastra2, runtimeContext }) => {
    const logger4 = mastra2?.getLogger();
    logger4?.info("\u{1F527} [PreferencesTool] Starting execution", { action: context.action });
    const userId = context.userId || runtimeContext?.resourceId || "default-user";
    const PREFS_KEY = `user_preferences_${userId}`;
    logger4?.info("\u{1F4DD} [PreferencesTool] User context", { userId, prefsKey: PREFS_KEY });
    try {
      let currentPref = "default";
      try {
        const memory2 = mastra2?.memory;
        if (memory2) {
          const messages = await memory2.getMessages({
            resourceId: userId,
            threadId: PREFS_KEY
          });
          if (messages && messages.length > 0) {
            const lastMessage = messages[messages.length - 1];
            if (lastMessage.content) {
              const prefs = JSON.parse(lastMessage.content);
              currentPref = prefs.linkPreference || "default";
            }
          }
        }
      } catch (e) {
        logger4?.info("[PreferencesTool] No existing preferences found, using defaults");
        currentPref = "default";
      }
      let message = "";
      let success = true;
      if (context.action === "set" && context.linkPreference) {
        currentPref = context.linkPreference;
        const memory2 = mastra2?.memory;
        if (memory2) {
          await memory2.saveMessages({
            messages: [{
              role: "assistant",
              content: JSON.stringify({ linkPreference: currentPref })
            }],
            resourceId: userId,
            threadId: PREFS_KEY
          });
          logger4?.info("\u{1F4BE} [PreferencesTool] Preferences saved", { userId, linkPreference: currentPref });
        }
        message = currentPref === "kraken" ? "\u2705 Links set to Kraken (crypto & stocks will link to kraken.com)" : "\u2705 Links set to default (crypto\u2192CoinGecko, stocks\u2192Yahoo Finance)";
      } else {
        message = currentPref === "kraken" ? "Current link preference: Kraken" : "Current link preference: Default (CoinGecko/Yahoo Finance)";
      }
      logger4?.info("\u2705 [PreferencesTool] Action completed", {
        action: context.action,
        userId,
        linkPreference: currentPref
      });
      return {
        success,
        linkPreference: currentPref,
        message
      };
    } catch (error) {
      logger4?.error("\u274C [PreferencesTool] Error", { error: error.message });
      throw new Error(`Preferences operation failed: ${error.message}`);
    }
  }
});

