import { createTool as createTool18 } from "@mastra/core/tools";
import { z as z19 } from "zod";
var alertsCache = /* @__PURE__ */ new Map();
var priceAlertTool = createTool18({
  id: "price-alert-tool",
  description: "Manage price alerts for crypto/stock assets. Create, list, and delete alerts that trigger Telegram notifications when price targets are reached.",
  inputSchema: z19.object({
    action: z19.enum(["create", "list", "delete", "check"]).describe("Action to perform: create new alert, list all alerts, delete alert by ID, or check prices against alerts"),
    userId: z19.string().optional().describe("User ID for the alert"),
    ticker: z19.string().optional().describe("Asset ticker symbol (e.g., BTC, ETH, AAPL)"),
    targetPrice: z19.number().optional().describe("Target price to trigger alert"),
    condition: z19.enum(["above", "below"]).optional().describe("Alert when price goes above or below target"),
    alertId: z19.string().optional().describe("Alert ID for deletion")
  }),
  outputSchema: z19.object({
    success: z19.boolean(),
    message: z19.string(),
    alerts: z19.array(z19.object({
      id: z19.string(),
      ticker: z19.string(),
      targetPrice: z19.number(),
      condition: z19.string(),
      createdAt: z19.string()
    })).optional(),
    triggeredAlerts: z19.array(z19.object({
      id: z19.string(),
      ticker: z19.string(),
      targetPrice: z19.number(),
      currentPrice: z19.number(),
      condition: z19.string()
    })).optional()
  }),
  execute: async ({ context, mastra: mastra2, runtimeContext }) => {
    const logger4 = mastra2?.getLogger();
    const { action, ticker, targetPrice, condition, alertId } = context;
    const userId = context.userId || runtimeContext?.resourceId || "default-user";
    const ALERTS_KEY = `price_alerts_${userId}`;
    logger4?.info("\u{1F514} [PriceAlerts] Starting alert operation", {
      action,
      userId,
      ticker,
      targetPrice,
      condition
    });
    try {
      let alerts = alertsCache.get(userId) || [];
      logger4?.info("\u{1F4DD} [PriceAlerts] Using in-memory cache", { count: alerts.length });
      switch (action) {
        case "create":
          if (!ticker || !targetPrice || !condition) {
            logger4?.error("\u274C [PriceAlerts] Missing required fields for create");
            return {
              success: false,
              message: "Missing ticker, targetPrice, or condition"
            };
          }
          const limitCheck = await checkSubscriptionLimit(userId, "alert");
          logger4?.info("\u{1F510} [PriceAlerts] Subscription check result", { userId, allowed: limitCheck.allowed, isPremium: limitCheck.isPremium });
          if (!limitCheck.allowed) {
            logger4?.warn("\u26A0\uFE0F [PriceAlerts] Alert limit exceeded", { userId, message: limitCheck.message });
            return {
              success: false,
              message: limitCheck.message || "Daily alert limit reached (3 alerts on free plan). Upgrade to Premium for unlimited alerts!"
            };
          }
          const newAlert = {
            id: `alert_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            ticker: ticker.toUpperCase(),
            targetPrice,
            condition,
            createdAt: (/* @__PURE__ */ new Date()).toISOString()
          };
          alerts.push(newAlert);
          alertsCache.set(userId, alerts);
          logger4?.info("\u2705 [PriceAlerts] Alert created successfully", { alert: newAlert });
          return {
            success: true,
            message: `Alert created: ${ticker} ${condition} $${targetPrice}`,
            alerts: [newAlert]
          };
        case "list":
          logger4?.info("\u{1F4CB} [PriceAlerts] Listing all alerts", { count: alerts.length });
          return {
            success: true,
            message: `Found ${alerts.length} alert(s)`,
            alerts
          };
        case "delete":
          if (!alertId) {
            logger4?.error("\u274C [PriceAlerts] Missing alert ID for deletion");
            return {
              success: false,
              message: "Missing alert ID"
            };
          }
          const initialCount = alerts.length;
          alerts = alerts.filter((a) => a.id !== alertId);
          alertsCache.set(userId, alerts);
          if (alerts.length === initialCount) {
            logger4?.warn("\u26A0\uFE0F [PriceAlerts] Alert not found", { alertId });
            return {
              success: false,
              message: "Alert not found"
            };
          }
          if (memory) {
            await memory.saveMessages({
              messages: [{
                role: "assistant",
                content: JSON.stringify(alerts)
              }],
              resourceId: userId,
              threadId: ALERTS_KEY
            });
          } else {
            alertsCache.set(userId, alerts);
          }
          logger4?.info("\u2705 [PriceAlerts] Alert deleted successfully", { alertId });
          return {
            success: true,
            message: "Alert deleted successfully",
            alerts
          };
        case "check":
          const { marketDataTool: marketDataTool2 } = await Promise.resolve().then(() => (init_marketDataTool(), marketDataTool_exports));
          const triggeredAlerts = [];
          for (const alert of alerts) {
            try {
              const marketData = await marketDataTool2.execute({
                context: { ticker: alert.ticker, days: 1 },
                mastra: mastra2,
                runtimeContext: null
              });
              if (marketData && marketData.currentPrice) {
                const currentPrice = marketData.currentPrice;
                const shouldTrigger = alert.condition === "above" && currentPrice >= alert.targetPrice || alert.condition === "below" && currentPrice <= alert.targetPrice;
                if (shouldTrigger) {
                  triggeredAlerts.push({
                    ...alert,
                    currentPrice
                  });
                  logger4?.info("\u{1F3AF} [PriceAlerts] Alert triggered!", {
                    ticker: alert.ticker,
                    targetPrice: alert.targetPrice,
                    currentPrice,
                    condition: alert.condition
                  });
                }
              }
            } catch (error) {
              logger4?.error("\u274C [PriceAlerts] Error checking price", {
                ticker: alert.ticker,
                error: error.message
              });
            }
          }
          logger4?.info("\u2705 [PriceAlerts] Price check complete", {
            totalAlerts: alerts.length,
            triggeredCount: triggeredAlerts.length
          });
          return {
            success: true,
            message: `Checked ${alerts.length} alerts, ${triggeredAlerts.length} triggered`,
            triggeredAlerts
          };
        default:
          logger4?.error("\u274C [PriceAlerts] Invalid action", { action });
          return {
            success: false,
            message: `Invalid action: ${action}`
          };
      }
    } catch (error) {
      logger4?.error("\u274C [PriceAlerts] Operation failed", { error: error.message });
      return {
        success: false,
        message: `Alert operation failed: ${error.message}`
      };
    }
  }
});

