// src/services/rpcService.ts
import axios16 from "axios";
import { Connection as Connection7, PublicKey as PublicKey7 } from "@solana/web3.js";
var HELIUS_API_KEY6 = process.env.HELIUS_API_KEY;
var DEFAULT_HELIUS_RPC = `https://mainnet.helius-rpc.com/?api-key=${HELIUS_API_KEY6}`;
var PUBLIC_RPC = "https://api.mainnet-beta.solana.com";
var DEFAULT_TX_OPTIONS = {
  priorityLevel: "auto",
  maxRetries: 3,
  skipPreflight: false,
  commitment: "confirmed"
};
var RPCService = class {
  primaryConnection;
  fallbackConnection;
  heliusEndpoint;
  customEndpoint = null;
  useCustomRPC = false;
  constructor() {
    this.heliusEndpoint = DEFAULT_HELIUS_RPC;
    this.primaryConnection = new Connection7(
      HELIUS_API_KEY6 ? DEFAULT_HELIUS_RPC : PUBLIC_RPC,
      { commitment: "confirmed" }
    );
    this.fallbackConnection = new Connection7(PUBLIC_RPC, { commitment: "confirmed" });
    console.log(`[RPC] Initialized with ${HELIUS_API_KEY6 ? "Helius" : "Public"} RPC`);
  }
  getActiveEndpoint() {
    if (this.useCustomRPC && this.customEndpoint) {
      return this.customEndpoint;
    }
    return this.heliusEndpoint;
  }
  getActiveConnection() {
    if (this.useCustomRPC && this.customEndpoint) {
      return new Connection7(this.customEndpoint, { commitment: "confirmed" });
    }
    return this.primaryConnection;
  }
  setCustomRPC(endpoint) {
    if (endpoint) {
      this.customEndpoint = endpoint;
      this.useCustomRPC = true;
      console.log(`[RPC] Switched to custom RPC: ${endpoint.substring(0, 50)}...`);
    } else {
      this.customEndpoint = null;
      this.useCustomRPC = false;
      console.log(`[RPC] Switched back to Helius RPC`);
    }
  }
  async getPriorityFeeEstimate(accountKeys, transaction) {
    if (!HELIUS_API_KEY6) {
      return this.getDefaultPriorityFees();
    }
    try {
      const payload = {
        jsonrpc: "2.0",
        id: "priority-fee-estimate",
        method: "getPriorityFeeEstimate",
        params: [
          {
            options: {
              includeAllPriorityFeeLevels: true,
              recommended: true
            }
          }
        ]
      };
      if (accountKeys && accountKeys.length > 0) {
        payload.params[0].accountKeys = accountKeys;
      } else if (transaction) {
        payload.params[0].transaction = transaction;
      }
      const response = await axios16.post(this.heliusEndpoint, payload, {
        headers: { "Content-Type": "application/json" },
        timeout: 5e3
      });
      const result = response.data?.result;
      if (result?.priorityFeeLevels) {
        const recommended = result.priorityFeeEstimate || result.priorityFeeLevels.medium;
        console.log(`[RPC] Priority fees - Min: ${result.priorityFeeLevels.min}, Med: ${result.priorityFeeLevels.medium}, High: ${result.priorityFeeLevels.high}`);
        return {
          priorityFeeLevels: result.priorityFeeLevels,
          recommendedFee: recommended,
          baseFee: result.priorityFeeLevels.min
        };
      }
      return this.getDefaultPriorityFees();
    } catch (error) {
      console.error("[RPC] Priority fee estimation failed:", error.message);
      return this.getDefaultPriorityFees();
    }
  }
  getDefaultPriorityFees() {
    return {
      priorityFeeLevels: {
        min: 1e3,
        low: 5e3,
        medium: 1e4,
        high: 5e4,
        veryHigh: 1e5,
        unsafeMax: 5e5
      },
      recommendedFee: 1e4,
      baseFee: 1e3
    };
  }
  async getOptimalPriorityFee(level, accountKeys) {
    const estimate = await this.getPriorityFeeEstimate(accountKeys);
    if (level === "auto") {
      return estimate.recommendedFee;
    }
    return estimate.priorityFeeLevels[level] || estimate.recommendedFee;
  }
  async sendTransaction(signedTransaction, options = {}) {
    const opts = { ...DEFAULT_TX_OPTIONS, ...options };
    const connection = this.getActiveConnection();
    let lastError = "";
    for (let attempt = 1; attempt <= opts.maxRetries; attempt++) {
      try {
        const txBuffer = Buffer.from(signedTransaction, "base64");
        const signature = await connection.sendRawTransaction(txBuffer, {
          skipPreflight: opts.skipPreflight,
          preflightCommitment: opts.commitment,
          maxRetries: 0
        });
        console.log(`[RPC] Transaction sent (attempt ${attempt}): ${signature}`);
        const confirmation = await connection.confirmTransaction(
          signature,
          opts.commitment
        );
        if (confirmation.value.err) {
          lastError = `Transaction failed: ${JSON.stringify(confirmation.value.err)}`;
          console.error(`[RPC] Confirmation error:`, lastError);
          continue;
        }
        console.log(`[RPC] Transaction confirmed: ${signature}`);
        return { success: true, signature };
      } catch (error) {
        lastError = error.message;
        console.error(`[RPC] Attempt ${attempt} failed:`, error.message);
        if (attempt < opts.maxRetries) {
          const delayMs = Math.min(1e3 * attempt, 3e3);
          await this.sleep(delayMs);
        }
      }
    }
    if (this.useCustomRPC) {
      console.log("[RPC] Custom RPC failed, falling back to Helius...");
      return this.sendTransactionWithFallback(signedTransaction, opts);
    }
    return { success: false, error: lastError };
  }
  async sendTransactionWithFallback(signedTransaction, options) {
    try {
      const txBuffer = Buffer.from(signedTransaction, "base64");
      const signature = await this.primaryConnection.sendRawTransaction(txBuffer, {
        skipPreflight: options.skipPreflight,
        preflightCommitment: options.commitment,
        maxRetries: 2
      });
      const confirmation = await this.primaryConnection.confirmTransaction(
        signature,
        options.commitment
      );
      if (confirmation.value.err) {
        return {
          success: false,
          error: `Fallback failed: ${JSON.stringify(confirmation.value.err)}`
        };
      }
      return { success: true, signature };
    } catch (error) {
      return { success: false, error: `Fallback failed: ${error.message}` };
    }
  }
  async getLatestBlockhash() {
    const connection = this.getActiveConnection();
    const result = await connection.getLatestBlockhash("confirmed");
    return {
      blockhash: result.blockhash,
      lastValidBlockHeight: result.lastValidBlockHeight
    };
  }
  async getBalance(walletAddress) {
    try {
      const connection = this.getActiveConnection();
      const pubkey = new PublicKey7(walletAddress);
      const balance = await connection.getBalance(pubkey);
      return balance / 1e9;
    } catch (error) {
      console.error("[RPC] Balance check failed:", error);
      return 0;
    }
  }
  async getSlot() {
    const connection = this.getActiveConnection();
    return connection.getSlot();
  }
  async healthCheck() {
    const startTime = Date.now();
    try {
      const connection = this.getActiveConnection();
      await connection.getSlot();
      const latencyMs = Date.now() - startTime;
      let status = "healthy";
      if (latencyMs > 2e3) status = "degraded";
      if (latencyMs > 5e3) status = "unhealthy";
      return {
        status,
        latencyMs,
        endpoint: this.useCustomRPC ? "Custom RPC" : "Helius",
        type: this.useCustomRPC ? "custom" : HELIUS_API_KEY6 ? "helius" : "public"
      };
    } catch (error) {
      return {
        status: "unhealthy",
        latencyMs: Date.now() - startTime,
        endpoint: this.useCustomRPC ? "Custom RPC" : "Helius",
        type: this.useCustomRPC ? "custom" : HELIUS_API_KEY6 ? "helius" : "public"
      };
    }
  }
  getRPCInfo() {
    return {
      active: this.useCustomRPC ? "Custom" : HELIUS_API_KEY6 ? "Helius Premium" : "Public",
      type: this.useCustomRPC ? "custom" : HELIUS_API_KEY6 ? "helius" : "public",
      hasHelius: !!HELIUS_API_KEY6,
      hasCustom: !!this.customEndpoint
    };
  }
  sleep(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
};
var rpcService = new RPCService();

