            previousWinRate: saPreviousRate !== null ? saPreviousRate.toFixed(1) : null,
            delta: saDelta !== null ? saDelta.toFixed(1) : null,
            trend: saTrend,
            currentSamples: saCurrentSamples,
            previousSamples: saPreviousSamples
