// src/mastra/routes/cryptoOnrampRoutes.ts
import Stripe4 from "stripe";
var stripe4 = new Stripe4(process.env.STRIPE_SECRET_KEY || process.env.STRIPE_LIVE_SECRET_KEY || "", {
  apiVersion: "2025-10-29.clover"
});
var SUPPORTED_NETWORKS = ["solana", "ethereum", "polygon", "base", "arbitrum"];
var SUPPORTED_CURRENCIES = {
  solana: ["sol", "usdc"],
  ethereum: ["eth", "usdc"],
  polygon: ["matic", "usdc"],
  base: ["eth", "usdc"],
  arbitrum: ["eth", "usdc"]
};
var cryptoOnrampRoutes = [
  {
    path: "/api/crypto/onramp/create-session",
    method: "POST",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      const logger4 = mastra2.getLogger();
      try {
        const {
          walletAddress,
          network = "solana",
          currency = "sol",
          amount,
          userId
        } = await c.req.json();
        if (!walletAddress) {
          return c.json({ error: "Wallet address required" }, 400);
        }
        if (!SUPPORTED_NETWORKS.includes(network)) {
          return c.json({
            error: `Network not supported. Use: ${SUPPORTED_NETWORKS.join(", ")}`
          }, 400);
        }
        const networkWallets = {};
        if (network === "solana") {
          networkWallets.solana = walletAddress;
        } else {
          networkWallets.ethereum = walletAddress;
        }
        const sessionParams = {
          wallet_addresses: networkWallets,
          destination_network: network,
          destination_currency: currency
        };
        if (amount) {
          sessionParams.source_amount = amount.toString();
          sessionParams.source_currency = "usd";
        }
        const session = await stripe4.crypto.onrampSessions.create(sessionParams);
        logger4?.info("\u2705 [Crypto Onramp] Session created", {
          sessionId: session.id,
          network,
          currency,
          userId
        });
        return c.json({
          success: true,
          clientSecret: session.client_secret,
          sessionId: session.id,
          redirectUrl: session.redirect_url
        });
      } catch (error) {
        logger4?.error("\u274C [Crypto Onramp] Create session error", { error: error.message });
        if (error.message?.includes("onramp")) {
          return c.json({
            error: "Crypto onramp not enabled. Please apply for access in Stripe Dashboard.",
            needsSetup: true
          }, 400);
        }
        return c.json({ error: error.message }, 500);
      }
    }
  },
  {
    path: "/api/crypto/onramp/session-status",
    method: "GET",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      const logger4 = mastra2.getLogger();
      try {
        const sessionId = c.req.query("sessionId");
        if (!sessionId) {
          return c.json({ error: "Session ID required" }, 400);
        }
        const session = await stripe4.crypto.onrampSessions.retrieve(sessionId);
        return c.json({
          success: true,
          status: session.status,
          destinationAmount: session.destination_amount,
          destinationCurrency: session.destination_currency,
          network: session.destination_network
        });
      } catch (error) {
        logger4?.error("\u274C [Crypto Onramp] Get session status error", { error: error.message });
        return c.json({ error: error.message }, 500);
      }
    }
  },
  {
    path: "/api/crypto/onramp/supported",
    method: "GET",
    createHandler: async () => async (c) => {
      return c.json({
        success: true,
        networks: SUPPORTED_NETWORKS,
        currencies: SUPPORTED_CURRENCIES,
        note: "Currently available for US customers only"
      });
    }
  }
];

// src/mastra/routes/swapRoutes.ts
import { Connection as Connection11, VersionedTransaction as VersionedTransaction4 } from "@solana/web3.js";
var HELIUS_API_KEY9 = process.env.HELIUS_API_KEY;
var SOLANA_RPC3 = HELIUS_API_KEY9 ? `https://mainnet.helius-rpc.com/?api-key=${HELIUS_API_KEY9}` : "https://api.mainnet-beta.solana.com";
var swapRoutes = [
  {
    path: "/api/swap/tokens",
    method: "GET",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      const logger4 = mastra2.getLogger();
      try {
        logger4?.info("\u{1F504} [Swap] Fetching token list from Jupiter");
        const response = await fetch("https://token.jup.ag/all");
        if (!response.ok) {
          throw new Error(`Jupiter token API error: ${response.status}`);
        }
        const allTokens = await response.json();
        const sortedTokens = allTokens.filter((token) => token.address && token.symbol && token.name).sort((a, b) => (b.daily_volume || 0) - (a.daily_volume || 0)).slice(0, 50).map((token) => ({
          address: token.address,
          symbol: token.symbol,
          name: token.name,
          decimals: token.decimals,
          logoURI: token.logoURI || null
        }));
        logger4?.info("\u2705 [Swap] Token list fetched", { count: sortedTokens.length });
        return c.json({
          success: true,
          tokens: sortedTokens
        });
      } catch (error) {
        logger4?.error("\u274C [Swap] Token list error", { error: error.message });
        return c.json({ error: error.message }, 500);
      }
    }
  },
  {
    path: "/api/swap/quote",
    method: "GET",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      const logger4 = mastra2.getLogger();
      try {
        const inputMint = c.req.query("inputMint");
        const outputMint = c.req.query("outputMint");
        const amount = c.req.query("amount");
        const slippageBps = c.req.query("slippageBps") || "50";
        if (!inputMint || !outputMint || !amount) {
          return c.json({
            error: "Missing required parameters: inputMint, outputMint, amount"
          }, 400);
        }
        logger4?.info("\u{1F504} [Swap] Getting quote from Jupiter", {
          inputMint,
          outputMint,
          amount,
          slippageBps
        });
        const quoteUrl = new URL("https://quote-api.jup.ag/v6/quote");
        quoteUrl.searchParams.set("inputMint", inputMint);
        quoteUrl.searchParams.set("outputMint", outputMint);
        quoteUrl.searchParams.set("amount", amount);
        quoteUrl.searchParams.set("slippageBps", slippageBps);
        const response = await fetch(quoteUrl.toString());
        if (!response.ok) {
          const errorText = await response.text();
          throw new Error(`Jupiter quote API error: ${response.status} - ${errorText}`);
        }
        const quoteResponse = await response.json();
        logger4?.info("\u2705 [Swap] Quote received", {
          inputAmount: quoteResponse.inAmount,
          outputAmount: quoteResponse.outAmount,
          priceImpactPct: quoteResponse.priceImpactPct
        });
        return c.json({
          success: true,
          inputAmount: quoteResponse.inAmount,
          outputAmount: quoteResponse.outAmount,
          priceImpactPct: quoteResponse.priceImpactPct,
          routePlan: quoteResponse.routePlan,
          quoteResponse
        });
      } catch (error) {
        logger4?.error("\u274C [Swap] Quote error", { error: error.message });
        return c.json({ error: error.message }, 500);
      }
    }
  },
  {
    path: "/api/swap/prepare",
    method: "POST",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      const logger4 = mastra2.getLogger();
      try {
        const { quoteResponse, userPublicKey } = await c.req.json();
        if (!quoteResponse) {
          return c.json({ error: "quoteResponse is required" }, 400);
        }
        if (!userPublicKey) {
          return c.json({ error: "userPublicKey is required" }, 400);
        }
        logger4?.info("\u{1F504} [Swap] Preparing swap transaction (non-custodial)", {
          userPublicKey,
          inputMint: quoteResponse.inputMint,
          outputMint: quoteResponse.outputMint
        });
        const swapResponse = await fetch("https://quote-api.jup.ag/v6/swap", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            quoteResponse,
            userPublicKey,
            wrapAndUnwrapSol: true,
            dynamicComputeUnitLimit: true,
            prioritizationFeeLamports: "auto"
          })
        });
        if (!swapResponse.ok) {
          const errorText = await swapResponse.text();
          throw new Error(`Jupiter swap API error: ${swapResponse.status} - ${errorText}`);
        }
        const { swapTransaction } = await swapResponse.json();
        logger4?.info("\u2705 [Swap] Transaction prepared - ready for client-side signing");
        return c.json({
          success: true,
          swapTransaction,
          message: "Sign this transaction client-side, then call /api/swap/broadcast"
        });
      } catch (error) {
        logger4?.error("\u274C [Swap] Prepare error", { error: error.message });
        return c.json({
          success: false,
          error: error.message
        }, 500);
      }
    }
  },
  {
    path: "/api/swap/broadcast",
    method: "POST",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      const logger4 = mastra2.getLogger();
      try {
        const { signedTransaction } = await c.req.json();
        if (!signedTransaction) {
          return c.json({ error: "signedTransaction (base64) is required" }, 400);
        }
        logger4?.info("\u{1F504} [Swap] Broadcasting signed transaction");
        const transactionBuf = Buffer.from(signedTransaction, "base64");
        const transaction = VersionedTransaction4.deserialize(transactionBuf);
        const connection = new Connection11(SOLANA_RPC3, "confirmed");
        const rawTransaction = transaction.serialize();
        const txHash = await connection.sendRawTransaction(rawTransaction, {
          skipPreflight: true,
          maxRetries: 2
        });
        await connection.confirmTransaction(txHash, "confirmed");
        const explorerUrl = `https://solscan.io/tx/${txHash}`;
        logger4?.info("\u2705 [Swap] Transaction successful", { txHash, explorerUrl });
        return c.json({
          success: true,
          txHash,
          explorerUrl
        });
      } catch (error) {
        logger4?.error("\u274C [Swap] Broadcast error", { error: error.message });
        return c.json({
          success: false,
          error: error.message
        }, 500);
      }
    }
  }
];

