// src/mastra/routes/taxRoutes.ts
init_client();
init_schema();
import { eq as eq35, and as and29, desc as desc27 } from "drizzle-orm";
var taxRoutes = [
  {
    path: "/api/tax/reports/:userId",
    method: "GET",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      try {
        const userId = c.req.param("userId");
        const year = parseInt(c.req.query("year") || (/* @__PURE__ */ new Date()).getFullYear().toString());
        const method = c.req.query("method") || "fifo";
        const transactions = await db.select().from(portfolioTransactions).where(eq35(portfolioTransactions.userId, userId)).orderBy(portfolioTransactions.timestamp);
        const yearTransactions = transactions.filter((tx) => {
          const txYear = new Date(tx.timestamp).getFullYear();
          return txYear === year;
        });
        let totalGains = 0;
        let totalLosses = 0;
        let shortTermGains = 0;
        let longTermGains = 0;
        const holdings = {};
        const taxEvents = [];
        for (const tx of yearTransactions) {
          const symbol = tx.symbol;
          if (!holdings[symbol]) {
            holdings[symbol] = { quantity: 0, costBasis: 0, purchases: [] };
          }
          if (tx.type === "buy") {
            const qty = parseFloat(tx.quantity || "0");
            const price = parseFloat(tx.price || "0");
            holdings[symbol].purchases.push({
              quantity: qty,
              price,
              date: tx.timestamp,
              totalCost: qty * price
            });
            holdings[symbol].quantity += qty;
            holdings[symbol].costBasis += qty * price;
          } else if (tx.type === "sell") {
            const sellQuantity = parseFloat(tx.quantity || "0");
            const sellPrice = parseFloat(tx.price || "0");
            const sellTotal = sellQuantity * sellPrice;
            let costBasisUsed = 0;
            let remainingToSell = sellQuantity;
            let purchaseDate = null;
            while (remainingToSell > 0 && holdings[symbol].purchases.length > 0) {
              const lotIndex = method === "lifo" ? holdings[symbol].purchases.length - 1 : 0;
              const lot = holdings[symbol].purchases[lotIndex];
              const takeFromLot = Math.min(remainingToSell, lot.quantity);
              costBasisUsed += takeFromLot * lot.price;
              purchaseDate = purchaseDate || new Date(lot.date);
              lot.quantity -= takeFromLot;
              remainingToSell -= takeFromLot;
              if (lot.quantity <= 0) {
                if (method === "lifo") {
                  holdings[symbol].purchases.pop();
                } else {
                  holdings[symbol].purchases.shift();
                }
              }
            }
            const gain = sellTotal - costBasisUsed;
            const sellDate = new Date(tx.timestamp);
            const holdingDays = purchaseDate ? Math.floor((sellDate.getTime() - purchaseDate.getTime()) / (1e3 * 60 * 60 * 24)) : 0;
            const isLongTerm = holdingDays > 365;
            if (gain > 0) {
              totalGains += gain;
              if (isLongTerm) longTermGains += gain;
              else shortTermGains += gain;
            } else {
              totalLosses += Math.abs(gain);
            }
            taxEvents.push({
              date: tx.timestamp,
              symbol,
              type: "sell",
              quantity: sellQuantity,
              proceeds: sellTotal,
              costBasis: costBasisUsed,
              gainLoss: gain,
              term: isLongTerm ? "long" : "short",
              holdingDays
            });
            holdings[symbol].quantity -= sellQuantity;
            holdings[symbol].costBasis -= costBasisUsed;
          }
        }
        return c.json({
          year,
          method,
          summary: {
            totalGains,
            totalLosses,
            netGainLoss: totalGains - totalLosses,
            shortTermGains,
            longTermGains,
            taxableEvents: taxEvents.length
          },
          taxEvents,
          holdings: Object.entries(holdings).map(([symbol, data]) => ({
            symbol,
            quantity: data.quantity,
            costBasis: data.costBasis,
            avgCostPerUnit: data.quantity > 0 ? data.costBasis / data.quantity : 0
          }))
        });
      } catch (error) {
        console.error("Tax report error:", error);
        return c.json({ error: "Failed to generate tax report" }, 500);
      }
    }
  },
  {
    path: "/api/tax/export/:userId",
    method: "GET",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      try {
        const userId = c.req.param("userId");
        const year = c.req.query("year") || (/* @__PURE__ */ new Date()).getFullYear().toString();
        const format = c.req.query("format") || "csv";
        const transactions = await db.select().from(portfolioTransactions).where(eq35(portfolioTransactions.userId, userId));
        const yearTransactions = transactions.filter((tx) => {
          const txYear = new Date(tx.timestamp).getFullYear();
          return txYear === parseInt(year);
        });
        if (format === "csv") {
          let csv = "Date,Type,Symbol,Quantity,Price,Total\n";
          for (const tx of yearTransactions) {
            const total = parseFloat(tx.quantity || "0") * parseFloat(tx.price || "0");
            csv += `${tx.timestamp},${tx.type},${tx.symbol},${tx.quantity},${tx.price},${total}
`;
          }
          c.header("Content-Type", "text/csv");
          c.header("Content-Disposition", `attachment; filename="tax_report_${year}.csv"`);
          return c.body(csv);
        } else if (format === "turbotax") {
          let txf = "!MTAX01\nVERSION 042\n";
          for (const tx of yearTransactions) {
            if (tx.type === "sell") {
              const total = parseFloat(tx.quantity || "0") * parseFloat(tx.price || "0");
              txf += `TD
N323
C1
L1
P${tx.symbol}
D${tx.timestamp}
$${total}
^
`;
            }
          }
          c.header("Content-Type", "application/x-txf");
          c.header("Content-Disposition", `attachment; filename="tax_report_${year}.txf"`);
          return c.body(txf);
        }
        return c.json({ error: "Invalid format" }, 400);
      } catch (error) {
        console.error("Tax export error:", error);
        return c.json({ error: "Failed to export tax data" }, 500);
      }
    }
  },
  {
    path: "/api/tax/cost-basis/:userId/:symbol",
    method: "GET",
    createHandler: async ({ mastra: mastra2 }) => async (c) => {
      try {
        const userId = c.req.param("userId");
        const symbol = c.req.param("symbol");
        const method = c.req.query("method") || "fifo";
        const transactions = await db.select().from(portfolioTransactions).where(and29(
          eq35(portfolioTransactions.userId, userId),
          eq35(portfolioTransactions.symbol, symbol)
        )).orderBy(method === "lifo" ? desc27(portfolioTransactions.timestamp) : portfolioTransactions.timestamp);
        let totalQuantity = 0;
        let totalCostBasis = 0;
        const lots = [];
        for (const tx of transactions) {
          if (tx.type === "buy") {
            const quantity = parseFloat(tx.quantity || "0");
            const price = parseFloat(tx.price || "0");
            totalQuantity += quantity;
            totalCostBasis += quantity * price;
            lots.push({
              date: tx.timestamp,
              quantity,
              price,
              costBasis: quantity * price
            });
          }
        }
        return c.json({
          symbol,
          method,
          totalQuantity,
          totalCostBasis,
          averageCostPerUnit: totalQuantity > 0 ? totalCostBasis / totalQuantity : 0,
          lots
        });
      } catch (error) {
        console.error("Cost basis error:", error);
        return c.json({ error: "Failed to calculate cost basis" }, 500);
      }
    }
  }
];

// src/mastra/routes/copyTradingRoutes.ts
init_client();
