        createHandler: async ({ mastra: mastra2 }) => async (c) => {
          const logger4 = mastra2.getLogger();
          const coinId = c.req.param("coinId");
          const interval = c.req.query("interval") || "1d";
          const limit = parseInt(c.req.query("limit") || "730");
          try {
            const daysMap = {
              "1m": 1,
              "5m": 1,
              "1h": 1,
              "6h": 1,
              "1d": 365,
              "1w": 365,
              "30d": 30,
              "1y": 365,
              "all": 730
            };
            const days = daysMap[interval] || 365;
            const chartData = await coinGeckoClient.getMarketChart(coinId, days);
            const prices = chartData.prices || [];
            const candles = prices.slice(-limit).map((price, index) => ({
              date: new Date(price[0]),
              open: price[1],
              high: price[1] * 1.02,
              // Approximate
              low: price[1] * 0.98,
              // Approximate
              close: price[1],
              volume: 0
            }));
            return c.json(candles);
          } catch (error) {
            logger4?.error("Failed to fetch historical data:", { coinId, error: error.message });
            return c.json({ error: "Failed to fetch historical data" }, 500);
          }
        }
